size(400);

real g(real x)
{
	return sin(x) + cos(x);
}

draw(graph(g,-3*pi,3*pi,n=700,join=operator ..),red);
trig_axes(-3*pi,3*pi,-2,2,pi/2,1);
layer();
rm_trig_labels(-5, 5, 2);
[/asy]

